@startuml
left to right direction
skinparam packageStyle rectangle
skinparam class {
  BackgroundColor White
  ArrowColor Black
  BorderColor Black
  FontColor Black
}

class "Transaction" as Transaction {
  <<abstract>>
  +Execute()
}

class "DepositTransaction" as DepositTransaction {
  +C
}

class "WithdrawalTransaction" as WithdrawalTransaction {
  +C
}

class "TransferTransaction" as TransferTransaction {
  +C
}

interface "DepositUI" as DepositUI {
  +I
  +RequestDepositAmount()
}

interface "WithdrawalUI" as WithdrawalUI {
  +I
  +RequestWithdrawalAmount()
}

interface "TransferUI" as TransferUI {
  +I
  +RequestTransferAmount()
}

interface "UI" as UI {
  +I
  +RequestDepositAmount()
  +RequestWithdrawalAmount()
  +RequestTransferAmount()
}

Transaction <|-- DepositTransaction
Transaction <|-- WithdrawalTransaction
Transaction <|-- TransferTransaction

DepositTransaction ..> DepositUI
WithdrawalTransaction ..> WithdrawalUI
TransferTransaction ..> TransferUI

DepositUI <|-- UI
WithdrawalUI <|-- UI
TransferUI <|-- UI

@enduml
